<body><style>.content-workspace{display:grid;gap:1rem;margin-top:1.25rem}.content-section-nav{display:flex;gap:.45rem;overflow:auto;padding:.15rem 0 .5rem}.content-section-nav button{min-height:44px;flex:0 0 auto;border:1px solid var(--line);border-radius:.55rem;background:var(--paper);padding:.55rem .75rem;font:700 .74rem var(--sans);text-align:left}.content-section-nav button.is-selected{border-color:var(--accent-dark);background:var(--pink)}.content-mode-body{min-width:0}.content-guide-tip{margin-top:.75rem!important;padding-top:.75rem;border-top:1px solid var(--line);color:var(--muted);font-size:.78rem}.content-management-page .section-management-layout{display:grid;gap:1rem}.content-management-page .section-management-list>li{box-shadow:0 .25rem .7rem rgb(30 20 23 / .035)}@media(min-width:900px){.content-workspace{grid-template-columns:13.5rem minmax(0,1fr) 17rem;align-items:start}.content-section-nav{position:sticky;top:1rem;display:grid;overflow:visible;padding:0}.content-section-nav button{width:100%}.content-management-context{display:none}.content-section-guide{position:sticky;top:1rem;margin:0}.content-management-page .section-management-layout{grid-template-columns:minmax(19rem,.7fr) minmax(0,1.3fr);align-items:start}.content-management-page .section-management-list{position:sticky;top:1rem}}@media(max-width:899px){.content-section-guide{display:none}.content-management-page .section-management-header{align-items:start;flex-direction:column}.content-management-page .section-management-header .admin-action{width:100%}}</style><style>.admin-menu-button,.admin-navigation-backdrop{display:none}@media(max-width:639px){.admin-menu-button{display:inline-flex;align-items:center;justify-content:center;gap:.35rem;min-height:44px;border:1px solid var(--line);border-radius:.45rem;background:var(--paper);padding:.45rem .65rem;font:700 .72rem var(--sans)}.admin-menu-button svg{width:1rem;height:1rem;fill:none;stroke:currentColor;stroke-width:1.8}.admin-sidebar nav{display:none!important}.admin-sidebar nav.is-open{position:fixed;z-index:120;inset:0 auto 0 0;display:grid!important;align-content:start;width:min(86vw,20rem);overflow:auto;margin:0!important;padding:5rem 1rem 1rem!important;background:var(--paper);box-shadow:1rem 0 2rem rgb(30 20 23 / .18)}.admin-sidebar nav.is-open a{min-height:48px!important;font-size:.86rem}.admin-navigation-backdrop{position:fixed;z-index:110;inset:0;display:block;border:0;background:rgb(30 23 25 / .44)}}</style><main id="admin-app"></main></body>
